import{_ as a,o as i,c as t,ae as n}from"./chunks/framework.7dB773Za.js";const h=JSON.parse('{"title":"Performance","description":"","frontmatter":{},"headers":[],"relativePath":"misc/performance.md","filePath":"misc/performance.md"}'),o={name:"misc/performance.md"};function l(r,e,s,c,d,f){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h1><p>Response time is highly dependent on your individual config, so here are just a few notes:</p><ul><li>Obviously, more things on a page will make it slower, leading to more queries/image transforms (Sorry for this trivial statement...).</li><li>So it is all about finding a balance.</li><li>We found that people prefer a longer initial load time and having anything they need available from the start, rather than jumping around between different pages.</li><li>Better hosting always pays off.</li><li>By default, all content on a page is rendered server side (including all tabs).</li><li>Set the <a href="./../config/common.html#loadsectionsasync">loadSectionsAsync</a> setting to <code>true</code> if the section html shall be loaded by ajax calls. The section will only be loaded if it is in the viewport.</li><li>Set the <a href="./../config/plugin-config.html#showloadingindicator">showLoadingIndicator</a> plugin setting to <code>true</code> if you want a visual clue while an ajax request is running.</li><li>Because single request will likely be fast, this can be somewhat confusing.</li><li>Transformed images are generated on the fly if they don&#39;t already exist, so a lower <a href="./../config/section-settings.html#limit">limit</a> can speed up things.</li><li>Images and their transforms are automatically eager loaded if defined via <a href="./../config/section-settings.html#imagefield">imageField</a> or <a href="./../config/section-settings.html#fallbackcimagefield">fallbackImageField</a>.</li><li>If you want to eager load other related elements, use the <a href="./../customize/events.html#modify-query">Section::EVENT_MODIFY_CONTENTOVERVIEW_QUERY</a> event or a <a href="./../dev/section.html#eager-loading">custom module</a>.</li><li>You can populate the <a href="./../config/common.html#custom">custom</a> setting in your config with any data in advance.</li><li>You can overwrite any class if you need some special handling.</li></ul>',3)])])}const g=a(o,[["render",l]]);export{h as __pageData,g as default};
